use std::collections::{HashMap, VecDeque};

fn solve(nums: Vec<i64>) -> i64 {
    let n = nums.len();
    if n == 1 {
        return 0;
    }

    // Precompute primes up to the maximum number in nums using Sieve of Eratosthenes
    let max_num = *nums.iter().max().unwrap() as usize;
    let mut is_prime = vec![true; max_num + 1];
    is_prime[0] = false;
    is_prime[1] = false;
    for i in 2..=(max_num as f64).sqrt() as usize {
        if is_prime[i] {
            for j in (i * i..=max_num).step_by(i) {
                is_prime[j] = false;
            }
        }
    }

    // Build a map from primes to their multiples in nums
    let mut prime_to_indices: HashMap<i64, Vec<usize>> = HashMap::new();
    for (i, &num) in nums.iter().enumerate() {
        if num <= 1 {
            continue;
        }
        if is_prime[num as usize] {
            prime_to_indices.entry(num).or_default().push(i);
        }
    }

    // BFS setup
    let mut visited = vec![false; n];
    let mut queue = VecDeque::new();
    queue.push_back((0, 0));
    visited[0] = true;

    while let Some((current, steps)) = queue.pop_front() {
        if current == n - 1 {
            return steps;
        }

        // Check adjacent moves
        if current + 1 < n && !visited[current + 1] {
            visited[current + 1] = true;
            queue.push_back((current + 1, steps + 1));
        }
        if current > 0 && !visited[current - 1] {
            visited[current - 1] = true;
            queue.push_back((current - 1, steps + 1));
        }

        // Check prime teleportation
        let num = nums[current];
        if num > 1 && is_prime[num as usize] {
            if let Some(indices) = prime_to_indices.get(&num) {
                for &j in indices {
                    if j != current && !visited[j] {
                        visited[j] = true;
                        queue.push_back((j, steps + 1));
                    }
                }
                // Clear to avoid reprocessing the same prime
                prime_to_indices.remove(&num);
            }
        }
    }

    -1 // in case it's unreachable (though problem says it's possible)
}
